    if (typeof value === "string" && isNaN(parseFloat(value))) return null;
    const numericValue: number = typeof value === "string" ? parseFloat(value) : value;
    if (fromUnit === toUnit) return numericValue;
    if (fromUnit === "cm" && toUnit === "m") return numericValue / 100;
    if (fromUnit === "kg" && toUnit === "g") return numericValue * 1000;
