class TaskManager {
    private tasks: Array<{ id: string; description: string; completed: boolean }> = [];

    public addTask(id: string, description: string): void {
        if (this.tasks.some(task => task.id === id)) {
            throw new Error("Task ID already exists");
        }
        this.tasks.push({ id, description, completed: false });
    }

    public completeTask(id: string): boolean {
        const task = this.tasks.find(task => task.id === id);
        if (!task) return false;
        task.completed = true;
        return true;
    }

    public getPendingTasks(): Array<{ id: string; description: string }> {
        return this.tasks
            .filter(task => !task.completed)
            .map(task => ({ id: task.id, description: task.description }));
    }
}

