class PasswordValidator {
    private readonly minLength: number;
    private readonly requireSpecialChars: boolean;

    constructor(minLength: number = 8, requireSpecialChars: boolean = true) {
        this.minLength = minLength;
        this.requireSpecialChars = requireSpecialChars;
    }

    public validate(password: string): { isValid: boolean; errors?: string[] } {
        const errors: string[] = [];

        if (password.length < this.minLength) {
            errors.push(`Password must be at least ${this.minLength} characters long`);
        }

        if (this.requireSpecialChars && !/[!@#$%^&*(),.?":{}|<>]/.test(password)) {
            errors.push("Password must contain at least one special character");
        }

        return { isValid: errors.length === 0, errors };
    }

    public getRequirements(): { minLength: number; requireSpecialChars: boolean } {
        return { minLength: this.minLength, requireSpecialChars: this.requireSpecialChars };
    }
}

