const retryOperation = <T>(
  operation: (attempt: number) => T,
  maxAttempts: number,
  delayMs: number
): Promise<T> => {
  return new Promise<T>((resolve, reject) => {
    const attempt = (currentAttempt: number): void => {
      try {
        const result: T = operation(currentAttempt);
        resolve(result);
      } catch (error) {
        if (currentAttempt >= maxAttempts) {
          reject(error);
        } else {
          setTimeout(() => attempt(currentAttempt + 1), delayMs);
        }
      }
    };
    attempt(1);
  });
};

const createMemoizer = <T, U>(fn: (arg: T) => U): ((arg: T) => U) => {
