const partitionBy = <T, K extends keyof any>(
  items: T[],
  keyFn: (item: T) => K
): Record<K, T[]> => {
  return items.reduce((acc: Record<K, T[]>, item: T): Record<K, T[]> => {
    const key: K = keyFn(item);
    if (!acc[key]) {
      acc[key] = [];
    }
    acc[key].push(item);
    return acc;
  }, {} as Record<K, T[]>);
};

const createDebouncer = <T, U>(
  fn: (arg: T) => U,
  delayMs: number
): ((arg: T) => void) => {
  let timeoutId: ReturnType<typeof setTimeout> | null = null;
  return (arg: T): void => {
    if (timeoutId !== null) {
      clearTimeout(timeoutId);
    }
    timeoutId = setTimeout((): void => {
      fn(arg);
      timeoutId = null;
    }, delayMs);
  };
};

