function divideNumbers(numerator: number, denominator: number): number | RangeError {
    if (denominator === 0) {
        return new RangeError("Denominator cannot be zero");
    }
    if (numerator < Number.MIN_SAFE_INTEGER || denominator < Number.MIN_SAFE_INTEGER ||
        numerator > Number.MAX_SAFE_INTEGER || denominator > Number.MAX_SAFE_INTEGER) {
        return new RangeError("Numbers out of safe integer range");
    }
    return numerator / denominator;
}

type FetchResult<T> = { kind: "success"; data: T } | { kind: "error"; error: Error; status?: number };

async function fetchWithTimeout<T>(url: string, timeoutMs: number = 5000): Promise<FetchResult<T>> {
    const controller: AbortController = new AbortController();
    const timeoutId: NodeJS.Timeout = setTimeout(() => controller.abort(), timeoutMs);

    try {
        const response: Response = await fetch(url, { signal: controller.signal });
        clearTimeout(timeoutId);
        if (!response.ok) return { kind: "error", error: new Error(`HTTP ${response.status}`), status: response.status };
        const data: T = await response.json();
        return { kind: "success", data };
    } catch (error) {
        clearTimeout(timeoutId);
        return { kind: "error", error: error instanceof Error ? error : new Error("Unknown fetch error") };
    }
}

function validateEmail(email: string): { valid: true; normalized: string } | { valid: false; reason: "empty" | "invalid" } {
    if (email.trim().length === 0) return { valid: false, reason: "empty" };
    const normalized: string = email.trim().toLowerCase();
    const emailRegex: RegExp = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(normalized)
        ? { valid: true, normalized }
        : { valid: false, reason: "invalid" };
}

type FileReadResult = { content: string } | { error: Error; code: "not_found" | "permission" | "unknown" };

function readFileSafely(path: string): FileReadResult {
    const fs = require('fs');
    try {
        if (!fs.existsSync(path)) return { error: new Error("File not found"), code: "not_found" };
        const content: string = fs.readFileSync(path, 'utf-8');
        return { content };
    } catch (error) {
        if (error instanceof Error && 'code' in error) {
            return { error, code: error.code === 'EACCES' ? "permission" : "unknown" };
        }
        return { error: new Error("Unknown file read error"), code: "unknown" };
    }
}

