type DatabaseInsertResult = { success: true; id: string } | { success: false; error: "duplicate" | "validation" | "db_error" };

async function insertUser(db: { query: (sql: string, values: any[]) => Promise<any> },
                         user: { email: string; name: string }): Promise<DatabaseInsertResult> {
    if (!user.email.includes('@')) return { success: false, error: "validation" };

    try {
        const result = await db.query(
            "INSERT INTO users (email, name) VALUES (?, ?) ON CONFLICT (email) DO NOTHING RETURNING id",
            [user.email, user.name]
        );
        if (result.rowCount === 0) return { success: false, error: "duplicate" };
        return { success: true, id: result.rows[0].id };
    } catch (error) {
        return { success: false, error: "db_error" };
    }
}

function calculateDiscount(price: number, discountPercent: number):
    { finalPrice: number; discountApplied: number } | { error: "invalid_price" | "invalid_discount" } {
    if (price <= 0) return { error: "invalid_price" };
    if (discountPercent < 0 || discountPercent > 100) return { error: "invalid_discount" };

    const discountAmount: number = price * (discountPercent / 100);
    const finalPrice: number = parseFloat((price - discountAmount).toFixed(2));
    return { finalPrice, discountApplied: discountAmount };
}

type ConfigLoadResult = { config: Record<string, unknown> } | { error: "file_error" | "parse_error"; details: string };

function loadConfig(filePath: string): ConfigLoadResult {
    try {
        const raw: string = require('fs').readFileSync(filePath, 'utf8');
        const parsed: unknown = JSON.parse(raw);

        if (typeof parsed !== 'object' || parsed === null || Array.isArray(parsed)) {
            return { error: "parse_error", details: "Config must be a JSON object" };
        }
        return { config: parsed as Record<string, unknown> };
    } catch (error) {
        return error instanceof Error
            ? { error: error.name.includes("JSON") ? "parse_error" : "file_error", details: error.message }
            : { error: "file_error", details: "Unknown error occurred" };
