function processPayment(amount: number, card: { number: string; expiry: string; cvv: string }):
    { status: "success"; transactionId: string } |
    { status: "failed"; reason: "invalid_card" | "insufficient_funds" | "processing_error" } {
    if (!/^\d{16}$/.test(card.number.replace(/\s/g, '')) ||
        !/^\d{2}\/\d{2}$/.test(card.expiry) ||
        !/^\d{3,4}$/.test(card.cvv)) {
        return { status: "failed", reason: "invalid_card" };
    }

    if (amount <= 0) return { status: "failed", reason: "processing_error" };
    if (amount > 10000) return { status: "failed", reason: "insufficient_funds" };

    const transactionId: string = `txn_${Math.random().toString(36).substring(2, 10)}`;
    return Math.random() > 0.1
        ? { status: "success", transactionId }
        : { status: "failed", reason: "processing_error" };
}

function findCommonElements<T>(setA: Set<T>, setB: Set<T>): Set<T> {
