function groupByKey<T, K extends keyof T>(items: T[], key: K): Map<T[K], T[]> {
    const grouped: Map<T[K], T[]> = new Map<T[K], T[]>();
    for (const item of items) {
        const keyValue: T[K] = item[key];
        const group: T[] = grouped.get(keyValue) ?? [];
        group.push(item);
        grouped.set(keyValue, group);
    }
    return grouped;
}

function findTopKFrequent<T>(items: T[], k: number): [T, number][] {
    const frequencyMap: Map<T, number> = new Map<T, number>();
    for (const item of items) {
        frequencyMap.set(item, (frequencyMap.get(item) ?? 0) + 1);
    }
    return Array.from(frequencyMap.entries())
        .sort((a, b) => b[1] - a[1])
        .slice(0, k);
}

function symmetricDifference<T>(setA: Set<T>, setB: Set<T>): Set<T> {
    const difference: Set<T> = new Set<T>();
    for (const element of setA) {
        if (!setB.has(element)) difference.add(element);
    }
    for (const element of setB) {
        if (!setA.has(element)) difference.add(element);
    }
    return difference;
}

function invertMap<K, V>(map: Map<K, V[]>): Map<V, K[]> {
    const inverted: Map<V, K[]> = new Map<V, K[]>();
    for (const [key, values] of map) {
        for (const value of values) {
            const keys: K[] = inverted.get(value) ?? [];
            keys.push(key);
            inverted.set(value, keys);
        }
    }
    return inverted;
}

function computeRunningAverages(numbers: number[]): number[] {
