    let sum: number = 0;
    for (let i: number = 0; i < numbers.length; i++) {
        sum += numbers[i];
        runningAverages.push(sum / (i + 1));
    }
    return runningAverages;
}

function findPairsWithSum(numbers: number[], target: number): Set<string> {
    const seen: Set<number> = new Set<number>();
    const pairs: Set<string> = new Set<string>();
    for (const num of numbers) {
        const complement: number = target - num;
        if (seen.has(complement)) {
            pairs.add(`[${Math.min(num, complement)},${Math.max(num, complement)}]`);
        }
        seen.add(num);
    }
    return pairs;
}

function deepMerge<T extends Record<string, any>, U extends Record<string, any>>(target: T, source: U): T & U {
    const output: Partial<T & U> = { ...target };
    for (const key in source) {
        if (source[key] instanceof Object && key in target) {
            output[key] = deepMerge(target[key], source[key]);
        } else {
            output[key] = source[key];
        }
    }
    return output as T & U;
}

function debounce<T extends (...args: any[]) => any>(
    func: T,
    wait: number,
    immediate: boolean = false
): (...args: Parameters<T>) => void {
    let timeout: ReturnType<typeof setTimeout> | null = null;
    return function(this: any, ...args: Parameters<T>): void {
        const context = this;
        const later = () => {
            timeout = null;
            if (!immediate) func.apply(context, args);
        };
        const callNow = immediate && !timeout;
        if (timeout) clearTimeout(timeout);
        timeout = setTimeout(later, wait);
        if (callNow) func.apply(context, args);
    };
}

function partitionArray<T, K extends keyof T>(
    array: T[],
    predicate: (item: T) => boolean
): [T[], T[]] {
    const truthy: T[] = [];
    const falsy: T[] = [];
    for (const item of array) {
        if (predicate(item)) {
            truthy.push(item);
        } else {
            falsy.push(item);
        }
    }
    return [truthy, falsy];
}

function memoize<T extends (...args: any[]) => any>(
    fn: T,
    keyResolver?: (...args: Parameters<T>) => string
): (...args: Parameters<T>) => ReturnType<T> {
    const cache = new Map<string, ReturnType<T>>();
    return (...args: Parameters<T>): ReturnType<T> => {
        const key: string = keyResolver ? keyResolver(...args) : JSON.stringify(args);
        if (cache.has(key)) return cache.get(key)!;
        const result = fn(...args);
        cache.set(key, result);
        return result;
    };
}

function pluck<T, K extends keyof T>(
    items: T[],
    key: K
): Array<T[K]> {
    return items.map(item => item[key]);
}

function curry<N extends any[], R>(
    fn: (...args: N) => R,
    ...args1: Partial<N>
): N extends [...infer A, ...infer B]
    ? A extends N ? R : (...args2: B) => R
    : never {
    return (...args2: any[]) => {
        const combinedArgs = [...args1, ...args2];
        return combinedArgs.length >= fn.length
            ? fn(...combinedArgs as N)
            : curry(fn, ...combinedArgs);
    } as any;
}

function groupBy<T, K extends keyof any>(
    array: T[],
    keySelector: (item: T) => K
): Record<K, T[]> {
    return array.reduce<Record<K, T[]>>((acc, item) => {
        const key: K = keySelector(item);
        if (!acc[key]) acc[key] = [];
        acc[key].push(item);
        return acc;
    }, {} as Record<K, T[]>);
}

function tryCatch<T extends (...args: any[]) => any>(
    fn: T,
    fallback: ReturnType<T> | ((error: unknown) => ReturnType<T>)
): (...args: Parameters<T>) => ReturnType<T> {
    return (...args: Parameters<T>): ReturnType<T> => {
        try {
            return fn(...args);
        } catch (error) {
            return typeof fallback === 'function'
                ? (fallback as Function)(error)
                : fallback;
        }
    };
}

function zipObject<K extends string | number | symbol, V>(
    keys: K[],
    values: V[]
): Record<K, V> {
    if (keys.length !== values.length) {
        throw new Error("Keys and values arrays must be of equal length");
    }
    return keys.reduce<Record<K, V>>((obj, key, index) => {
        obj[key] = values[index];
        return obj;
    }, {} as Record<K, V>);
}

function chainAsync<T, R>(
    initialValue: T,
    ...fns: Array<(input: Awaited<T>) => Promise<R> | R>
): Promise<Awaited<R>> {
    return fns.reduce(async (promise, fn) => {
        const result = await promise;
        return fn(result);
    }, Promise.resolve(initialValue));
}

