    ttl: number;
}

const apiCache: Map<string, CacheEntry<unknown>> = new Map();

async function fetchWithCache<T>(
    key: string,
    fetchFn: () => Promise<T>,
    ttlMs: number = 300000
): Promise<T> {
    const cached: CacheEntry<T> | undefined = apiCache.get(key) as CacheEntry<T> | undefined;
    if (cached && Date.now() - cached.timestamp < cached.ttl) {
        return cached.value;
    }

    const freshData: T = await fetchFn();
    apiCache.set(key, { value: freshData, timestamp: Date.now(), ttl: ttlMs });
    return freshData;
}

