from typing import List, Optional, Tuple

class Rectangle:
    def __init__(self, width: float, height: float, x: float = 0.0, y: float = 0.0) -> None:
        self.width: float = width
        self.height: float = height
        self.x: float = x
        self.y: float = y

    def area(self) -> float:
        return self.width * self.height

    def contains_point(self, point_x: float, point_y: float) -> bool:
        return (self.x <= point_x <= self.x + self.width and
                self.y <= point_y <= self.y + self.height)

    def intersection(self, other: 'Rectangle') -> Optional['Rectangle']:
        overlap_x = max(0, min(self.x + self.width, other.x + other.width) - max(self.x, other.x))
        overlap_y = max(0, min(self.y + self.height, other.y + other.height) - max(self.y, other.y))
        if overlap_x > 0 and overlap_y > 0:
            return Rectangle(overlap_x, overlap_y, max(self.x, other.x), max(self.y, other.y))
        return None

