def retry_on_failure(
    func: Callable[[], T],
    max_attempts: int = 3,
    handle_error: Optional[Callable[[Exception], None]] = None
) -> T:
    """Retry a function until it succeeds or max attempts are reached."""
    last_exception: Optional[Exception] = None
    for _ in range(max_attempts):
        try:
            return func()
        except Exception as e:
            last_exception = e
            if handle_error:
                handle_error(e)
    raise last_exception if last_exception else RuntimeError("Unknown error")

