def find_pairs_with_sum(nums: List[int], target: int) -> Set[Tuple[int, int]]:
    seen: Set[int] = set()
    pairs: Set[Tuple[int, int]] = set()

    for num in nums:
        complement: int = target - num
        if complement in seen:
            pair: Tuple[int, int] = tuple(sorted((num, complement)))
            pairs.add(pair)
        seen.add(num)

    return pairs

def topological_sort(edges: List[Tuple[int, int]]) -> List[int]:
    graph: Dict[int, List[int]] = {}
    in_degree: Dict[int, int] = {}

    for u, v in edges:
        graph.setdefault(u, []).append(v)
        in_degree[v] = in_degree.get(v, 0) + 1
        in_degree.setdefault(u, 0)

    queue: List[int] = [node for node in in_degree if in_degree[node] == 0]
    result: List[int] = []

    while queue:
        node: int = queue.pop(0)
        result.append(node)
        for neighbor in graph.get(node, []):
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    return result if len(result) == len(in_degree) else []

